var val = Services.getValue(LawReformActAmt.dataBinding);
var err = validateCurrencyValue(val, 99999999.99);
if( null == err )
{	Services.setValue(LawReformActAmt.dataBinding, WPU.formatToTwoDP(val));
}
return err;

