DefaultCurrency602.isReadOnly = function(){return true;}
DefaultCurrency602.isTemporary = function(){return true;}
DefaultCurrency602.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency602.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
